import React, { useState } from 'react';
import axios from 'axios';
import './App.css';

const COLORS = ['#6C63FF','#FF6584','#43C6AC','#F7971E','#a78bfa','#34d399','#fb923c','#60a5fa'];

const defaultProcesses = [
  { id: 1, name: 'P1', arrivalTime: 0, burstTime: 5 },
  { id: 2, name: 'P2', arrivalTime: 1, burstTime: 3 },
  { id: 3, name: 'P3', arrivalTime: 2, burstTime: 8 },
];

export default function App() {
  const [processes, setProcesses] = useState(defaultProcesses);
  const [quantum, setQuantum] = useState(2);
  const [result, setResult] = useState(null);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState('');

  const addProcess = () => {
    const id = processes.length + 1;
    setProcesses([...processes, { id, name: `P${id}`, arrivalTime: 0, burstTime: 1 }]);
  };

  const removeProcess = (id) => setProcesses(processes.filter(p => p.id !== id));

  const updateProcess = (id, field, value) => {
    setProcesses(processes.map(p =>
      p.id === id ? { ...p, [field]: field === 'name' ? value : Number(value) } : p
    ));
  };

  const simulate = async () => {
    setError('');
    setLoading(true);
    setResult(null);
    try {
      const res = await axios.post('http://localhost:5000/api/simulate', { processes, quantum: Number(quantum) });
      setResult(res.data);
    } catch (e) {
      setError(e.response?.data?.error || 'Cannot connect to backend. Make sure the server is running on port 5000.');
    }
    setLoading(false);
  };

  const reset = () => { setProcesses(defaultProcesses); setQuantum(2); setResult(null); setError(''); };

  const colorMap = {};
  processes.forEach((p, i) => { colorMap[p.name] = COLORS[i % COLORS.length]; });

  const totalTime = result ? result.timeline[result.timeline.length - 1]?.end || 1 : 1;

  return (
    <div className="app">
      {/* Header */}
      <header className="header">
        <div className="header-inner">
          <div className="logo">
            <span className="logo-icon">⟳</span>
            <span className="logo-text">RoundRobin<span className="logo-accent">.sim</span></span>
          </div>
          <p className="header-sub">CPU Scheduling Visualizer</p>
        </div>
      </header>

      <main className="main">
        {/* Input Panel */}
        <section className="card input-card">
          <div className="card-header">
            <h2>Processes</h2>
            <div className="quantum-row">
              <label>Time Quantum (Q)</label>
              <input
                type="number" min="1" value={quantum}
                onChange={e => setQuantum(e.target.value)}
                className="quantum-input"
              />
            </div>
          </div>

          <div className="table-wrap">
            <table className="process-table">
              <thead>
                <tr>
                  <th></th>
                  <th>Name</th>
                  <th>Arrival Time</th>
                  <th>Burst Time</th>
                  <th></th>
                </tr>
              </thead>
              <tbody>
                {processes.map((p, i) => (
                  <tr key={p.id}>
                    <td><span className="dot" style={{ background: COLORS[i % COLORS.length] }} /></td>
                    <td>
                      <input className="cell-input" value={p.name}
                        onChange={e => updateProcess(p.id, 'name', e.target.value)} />
                    </td>
                    <td>
                      <input className="cell-input" type="number" min="0" value={p.arrivalTime}
                        onChange={e => updateProcess(p.id, 'arrivalTime', e.target.value)} />
                    </td>
                    <td>
                      <input className="cell-input" type="number" min="1" value={p.burstTime}
                        onChange={e => updateProcess(p.id, 'burstTime', e.target.value)} />
                    </td>
                    <td>
                      <button className="remove-btn" onClick={() => removeProcess(p.id)}>✕</button>
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>

          <div className="btn-row">
            <button className="btn-secondary" onClick={addProcess}>+ Add Process</button>
            <button className="btn-secondary" onClick={reset}>Reset</button>
            <button className="btn-primary" onClick={simulate} disabled={loading}>
              {loading ? 'Simulating...' : '▶  Run Simulation'}
            </button>
          </div>

          {error && <div className="error-box">{error}</div>}
        </section>

        {/* Results */}
        {result && (
          <>
            {/* Gantt Chart */}
            <section className="card">
              <h2 className="section-title">Gantt Chart</h2>
              <div className="gantt-wrap">
                <div className="gantt-bar">
                  {result.timeline.map((block, i) => {
                    const width = ((block.end - block.start) / totalTime) * 100;
                    const isIdle = block.process === 'Idle';
                    return (
                      <div
                        key={i}
                        className="gantt-block"
                        style={{
                          width: `${width}%`,
                          background: isIdle ? '#2a2a3a' : colorMap[block.process] || '#6C63FF',
                          opacity: isIdle ? 0.5 : 1,
                        }}
                        title={`${block.process}: ${block.start} → ${block.end}`}
                      >
                        <span className="gantt-label">{block.process}</span>
                      </div>
                    );
                  })}
                </div>
                <div className="gantt-timeline">
                  {result.timeline.map((block, i) => (
                    <div key={i} className="gantt-tick" style={{ width: `${((block.end - block.start) / totalTime) * 100}%` }}>
                      <span className="tick-label">{block.start}</span>
                    </div>
                  ))}
                  <span className="tick-label tick-end">{totalTime}</span>
                </div>
              </div>
            </section>

            {/* Stats Table */}
            <section className="card">
              <h2 className="section-title">Process Statistics</h2>
              <div className="table-wrap">
                <table className="result-table">
                  <thead>
                    <tr>
                      <th></th>
                      <th>Process</th>
                      <th>Arrival</th>
                      <th>Burst</th>
                      <th>Completion</th>
                      <th>Turnaround</th>
                      <th>Waiting</th>
                    </tr>
                  </thead>
                  <tbody>
                    {result.results.map((r, i) => (
                      <tr key={r.id}>
                        <td><span className="dot" style={{ background: colorMap[r.name] || COLORS[i % COLORS.length] }} /></td>
                        <td className="proc-name">{r.name}</td>
                        <td>{r.arrivalTime}</td>
                        <td>{r.burstTime}</td>
                        <td>{r.completionTime}</td>
                        <td>{r.turnaroundTime}</td>
                        <td className="waiting">{r.waitingTime}</td>
                      </tr>
                    ))}
                  </tbody>
                </table>
              </div>

              <div className="averages">
                <div className="avg-box">
                  <span className="avg-label">Avg Waiting Time</span>
                  <span className="avg-value">{result.avgWaiting.toFixed(2)}</span>
                </div>
                <div className="avg-box">
                  <span className="avg-label">Avg Turnaround Time</span>
                  <span className="avg-value">{result.avgTurnaround.toFixed(2)}</span>
                </div>
              </div>
            </section>
          </>
        )}
      </main>
    </div>
  );
}
